//go:build vectors

package ingest

import (
	"context"
	"fmt"
	"log/slog"
	"os"
	"path/filepath"
	"time"

	"github.com/a<HOME>/agentic-rag-mcp/internal/config"
	"github.com/a<HOME>/agentic-rag-mcp/internal/domain"
	"github.com/a<HOME>/agentic-rag-mcp/internal/embedder"
)

// Pipeline orchestrates the indexing flow: security filter -> parse -> embed -> store.
type Pipeline struct {
	indexer  *Indexer
	embedder embedder.Embedder
	security config.SecurityConfig
	maxChunk int
}

// NewPipeline creates an indexing pipeline.
func NewPipeline(ix *Indexer, emb embedder.Embedder, secCfg config.SecurityConfig, maxChunkSize int) *Pipeline {
	if maxChunkSize <= 0 {
		maxChunkSize = 16000
	}
	return &Pipeline{
		indexer:  ix,
		embedder: emb,
		security: secCfg,
		maxChunk: maxChunkSize,
	}
}

// IndexPath indexes a single file or directory.
func (p *Pipeline) IndexPath(ctx context.Context, path, scope, kind string, force bool) (domain.IndexResult, error) {
	start := time.Now()

	info, err := os.Stat(path)
	if err != nil {
		return domain.IndexResult{}, fmt.Errorf("path does not exist: %s", path)
	}

	var result domain.IndexResult

	if info.IsDir() {
		result, err = p.indexDirectory(ctx, path, scope, kind, force)
	} else {
		result, err = p.indexFile(ctx, path, scope, kind, force)
	}

	if err != nil {
		return result, err
	}

	result.Duration = time.Since(start)
	return result, nil
}

// IndexGlobalSources indexes multiple paths with scope=global.
func (p *Pipeline) IndexGlobalSources(ctx context.Context, sources []string) (domain.IndexResult, error) {
	var combined domain.IndexResult
	start := time.Now()

	for _, src := range sources {
		if ctx.Err() != nil {
			return combined, ctx.Err()
		}

		info, err := os.Stat(src)
		if err != nil {
			slog.Warn("global source not found, skipping", "path", src, "error", err)
			continue
		}

		var result domain.IndexResult
		if info.IsDir() {
			result, err = p.indexDirectory(ctx, src, "global", "reference", false)
		} else {
			result, err = p.indexFile(ctx, src, "global", "reference", false)
		}

		if err != nil {
			slog.Error("indexing global source", "path", src, "error", err)
			continue
		}

		combined.Indexed += result.Indexed
		combined.Unchanged += result.Unchanged
		combined.Removed += result.Removed
		combined.Errors += result.Errors
		combined.Chunks += result.Chunks
		combined.Details = append(combined.Details, result.Details...)
		combined.FileErrors = append(combined.FileErrors, result.FileErrors...)
	}

	combined.Duration = time.Since(start)
	return combined, nil
}

// Indexer returns the underlying indexer for direct access (search, read, status).
func (p *Pipeline) Indexer() *Indexer {
	return p.indexer
}

func (p *Pipeline) indexFile(ctx context.Context, path, scope, kind string, force bool) (domain.IndexResult, error) {
	var result domain.IndexResult

	info, err := os.Stat(path)
	if err != nil {
		return result, fmt.Errorf("stat: %w", err)
	}

	// Security filter
	fr := SecurityFilter(path, info, p.security)
	if !fr.Allowed {
		return result, fmt.Errorf("file rejected: %s", fr.Reason)
	}

	// Read content
	content, err := os.ReadFile(path)
	if err != nil {
		return result, fmt.Errorf("reading file: %w", err)
	}

	// Hash check for incrementalism
	if !force && !p.indexer.HasChanged(path, content) {
		result.Unchanged = 1
		slug := domain.SlugFromPath(path)
		result.Details = append(result.Details, domain.IndexDetail{
			Path:   path,
			Slug:   slug,
			Action: "unchanged",
		})
		return result, nil
	}

	// Parse into chunks
	chunks := Parse(path, string(content), ParseOptions{
		MaxChunkSize: p.maxChunk,
		Scope:        scope,
		Kind:         kind,
	})

	if len(chunks) == 0 {
		result.Unchanged = 1
		return result, nil
	}

	// Embed chunks
	if err := p.embedChunks(ctx, chunks); err != nil {
		slog.Error("embedding failed, storing without vectors", "path", path, "error", err)
	}

	// Remove old chunks for this document before storing new ones
	slug := chunks[0].DocumentSlug
	if err := p.indexer.RemoveDocument(slug); err != nil {
		slog.Warn("removing old chunks", "slug", slug, "error", err)
	}

	// Store chunks
	if err := p.indexer.StoreChunks(chunks); err != nil {
		return result, fmt.Errorf("storing chunks: %w", err)
	}

	// Record hash
	p.indexer.RecordHash(path, content)

	effectiveScope := chunks[0].Scope
	effectiveKind := chunks[0].Kind

	result.Indexed = 1
	result.Chunks = len(chunks)
	result.Details = append(result.Details, domain.IndexDetail{
		Path:   path,
		Slug:   slug,
		Action: "indexed",
		Chunks: len(chunks),
		Scope:  effectiveScope,
		Kind:   effectiveKind,
	})

	slog.Info("indexed document",
		"path", path,
		"slug", slug,
		"chunks", len(chunks),
		"scope", effectiveScope,
		"kind", effectiveKind,
	)

	return result, nil
}

func (p *Pipeline) indexDirectory(ctx context.Context, dir, scope, kind string, force bool) (domain.IndexResult, error) {
	var result domain.IndexResult

	// Track which files we find on the filesystem
	filesFound := make(map[string]bool)

	err := filepath.Walk(dir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if ctx.Err() != nil {
			return ctx.Err()
		}

		// Skip blocked directories
		if info.IsDir() {
			name := info.Name()
			for _, blocked := range p.security.DirectoryBlocklist {
				if name == blocked {
					return filepath.SkipDir
				}
			}
			return nil
		}

		// Security filter
		fr := SecurityFilter(path, info, p.security)
		if !fr.Allowed {
			return nil
		}

		filesFound[path] = true

		fileResult, err := p.indexFile(ctx, path, scope, kind, force)
		if err != nil {
			slog.Error("indexing file", "path", path, "error", err)
			result.Errors++
			result.FileErrors = append(result.FileErrors, domain.IndexFileError{
				Path:    path,
				Message: err.Error(),
			})
			return nil
		}

		result.Indexed += fileResult.Indexed
		result.Unchanged += fileResult.Unchanged
		result.Chunks += fileResult.Chunks
		result.Details = append(result.Details, fileResult.Details...)
		return nil
	})

	if err != nil {
		return result, fmt.Errorf("walking directory: %w", err)
	}

	// Detect deleted files: paths in index that are no longer on filesystem
	indexed := p.indexer.IndexedPaths()
	for path := range indexed {
		// Only consider paths that were under this directory
		if !isSubpath(dir, path) {
			continue
		}
		if !filesFound[path] {
			slug := domain.SlugFromPath(path)
			if err := p.indexer.RemoveDocument(slug); err != nil {
				slog.Error("removing deleted document", "path", path, "error", err)
				continue
			}
			// Remove from hash tracking
			p.indexer.mu.Lock()
			delete(p.indexer.hashes, path)
			p.indexer.mu.Unlock()

			result.Removed++
			result.Details = append(result.Details, domain.IndexDetail{
				Path:   path,
				Slug:   slug,
				Action: "removed",
			})
			slog.Info("removed deleted document", "path", path, "slug", slug)
		}
	}

	return result, nil
}

func (p *Pipeline) embedChunks(ctx context.Context, chunks []domain.Chunk) error {
	if p.embedder == nil {
		return nil
	}

	texts := make([]string, len(chunks))
	for i, c := range chunks {
		texts[i] = c.Title + "\n\n" + c.Content
	}

	vectors, err := p.embedder.EmbedBatch(ctx, texts, embedder.PurposeIndex)
	if err != nil {
		return err
	}

	for i := range chunks {
		if i < len(vectors) {
			chunks[i].Vector = vectors[i]
		}
	}

	return nil
}

func isSubpath(parent, child string) bool {
	absParent, err := filepath.Abs(parent)
	if err != nil {
		return false
	}
	absChild, err := filepath.Abs(child)
	if err != nil {
		return false
	}
	rel, err := filepath.Rel(absParent, absChild)
	if err != nil {
		return false
	}
	return rel != ".." && len(rel) > 0 && rel[0] != '.'
}
